module top_module(
    invalid_out,
    in0,
    in1,
    in2,
    in3,
    sel
);output invalid_out;
    input in0;
    input in1;
    input in2;
    input in3;
    input [1:0] sel;

    reg invalid_out;

    always @(*) begin
        case (sel)
            2'b00: invalid_out = in0;
            2'b01: invalid_out = in1;
            2'b10: invalid_out = in2;
            2'b11: invalid_out = in3;
            default: invalid_out = 1'b0;
        endcase
    end

endmodule
